class Playground {
    async run(inputs) {
        const nums = inputs[0].split(',').map(Number);
        const target = parseInt(inputs[1]);

        this.nums.init(nums);
        this.seenNumbers.init([]);
        this.variables.init([['target', target]]);

        this.log("Starting Two Sum algorithm.");
        await this.await();

        for (let i = 0; i < nums.length; i++) {
            const currentNum = nums[i];
            this.variables.put('currentNum', currentNum);
            this.log(`Processing number ${currentNum} at index ${i}.`);
            this.nums.highlight(i, '#00e0ff'); // Highlight current number
            await this.await();

            const complement = target - currentNum;
            this.variables.put('complement', complement);
            this.log(`Calculating complement: ${target} - ${currentNum} = ${complement}.`);
            await this.await();

            if (this.seenNumbers.has(complement)) {
                const complementIndex = this.seenNumbers.get(complement);
                this.log(`Complement ${complement} found at index ${complementIndex}.`);
                this.seenNumbers.highlight(complement, '#00f5a0'); // Highlight complement in hashmap
                this.nums.highlight(complementIndex, '#00f5a0'); // Highlight complement in array
                this.nums.highlight(i, '#00f5a0'); // Highlight current number in array
                this.log(`Found pair: [${complementIndex}, ${i}]`);
                await this.await();
                return [complementIndex, i];
            } else {
                this.log(`Complement ${complement} not found. Adding ${currentNum} (index ${i}) to seen numbers.`);
                this.seenNumbers.put(currentNum, i);
                this.seenNumbers.highlight(currentNum, '#ffb703'); // Highlight added number in hashmap
                await this.await();
            }
            this.nums.highlight(i, '#6c8cff'); // Mark current number as processed
            await this.await();
        }

        this.log("No two sum solution found.");
        return [-1, -1]; // Should not happen based on problem constraints
    }
}
